// Advanced music metadata extraction
const msg = $input.first().json.message || $input.first().json.channel_post;
if (!msg) return [];

const text = msg.text || msg.caption || '';
const photo = msg.photo ? msg.photo[msg.photo.length - 1] : null;

// Multiple parsing patterns for different Coreradio formats
let artist = '', track = '', genre = '', country = '', year = '';

// Pattern 1: Artist - Track [Genre] (Country) | Year
const pattern1 = text.match(/^(.+?)\s+-\s+(.+?)\s*\[(.+?)\]\s*\((.+?)\)\s*\|\s*(\d{4})/);

// Pattern 2: Artist - Track [Genre] (Country)
const pattern2 = text.match(/^(.+?)\s+-\s+(.+?)\s*\[(.+?)\]\s*\((.+?)\)/);

// Pattern 3: Artist "Track" [Genre]
const pattern3 = text.match(/^(.+?)\s+"(.+?)"\s*\[(.+?)\]/);

if (pattern1) {
  [, artist, track, genre, country, year] = pattern1;
} else if (pattern2) {
  [, artist, track, genre, country] = pattern2;
} else if (pattern3) {
  [, artist, track, genre] = pattern3;
} else {
  // Fallback: first line is title
  const lines = text.split('\n');
  artist = lines[0].split(' - ')[0] || 'Unknown';
  track = lines[0].split(' - ')[1] || 'Unknown';
}

// Your favorite bands - EXPAND THIS LIST
const favoriteArtists = [
  'metallica', 'iron maiden', 'slayer', 'megadeth', 'anthrax',
  'pantera', 'tool', 'opeth', 'dream theater', 'porcupine tree',
  'gojira', 'mastodon', 'baroness', 'converge', 'neurosis',
  'isIS', 'cult of luna', 'amenra', 'neurosis', 'shellac',
  'big brave', 'sumac', 'old man gloom', 'the ocean',
  'leprous', 'haken', 'between the buried and me', 'meshuggah',
  'animals as leaders', 'plini', 'intervals', 'chon'
];

// Check for exact matches or close similarities
const artistLower = artist.toLowerCase();
const isDirectMatch = favoriteArtists.some(band => artistLower.includes(band));

return [{
  json: {
    rawText: text,
    artist: artist.trim(),
    track: track.trim(),
    genre: genre.trim(),
    country: country.trim(),
    year: year.trim(),
    photoFileId: photo?.file_id,
    photoUniqueId: photo?.file_unique_id,
    chatId: msg.chat?.id,
    messageId: msg.message_id,
    isDirectMatch: isDirectMatch,
    favoriteArtistsList: favoriteArtists.join(', ')
  }
}];

