// Parse Gemini response
const aiResponse = $input.first().json.content;
const originalData = $('Parse Music Data').item.json;

const decisionMatch = aiResponse.match(/DECISION:\s*(YES|NO)/i);
const confidenceMatch = aiResponse.match(/CONFIDENCE:\s*(\d+)/);
const reasonMatch = aiResponse.match(/REASON:\s*(.+?)(?=SIMILAR_TO:|$)/s);
const similarMatch = aiResponse.match(/SIMILAR_TO:\s*(.+)/);

const decision = decisionMatch ? decisionMatch[1].toUpperCase() : 'NO';
const confidence = confidenceMatch ? parseInt(confidenceMatch[1]) : 0;

return [{
  json: {
    ...originalData,
    aiDecision: decision,
    aiConfidence: confidence,
    aiReason: reasonMatch ? reasonMatch[1].trim() : 'No reason provided',
    aiSimilarTo: similarMatch ? similarMatch[1].trim() : 'None',
    shouldNotify: decision === 'YES' && confidence >= 7,
    fullAiResponse: aiResponse
  }
}];

